localparam int ARRAY_SIZE = 3;
logic [31:0] x[ARRAY_SIZE];
assign x[0] = '1;
genvar j;
for (j = 1; j < ARRAY_SIZE; j = j + 1)
 assign x[j] = x[j-1];

localparam int OUT_WIDTH = 4;
genvar i;
for (i = 0; i < ADDERS; i = i + 1)
 assign x[j][OUT_WIDTH*i +: OUT_WIDTH] = x[j-1][IN_WIDTH*i +: IN_WIDTH];

genvar i,j;
for (j = 1; j < ARRAY_SIZE; j = j + 1) begin
 localparam int IN_WIDTH = j + 1;
 for (i = 0; i < ADDERS; i = i + 1)
   assign x[j][OUT_WIDTH*i +: OUT_WIDTH] = x[j-1][2*IN_WIDTH*i +: IN_WIDTH];
end

logic [31:0] x[ARRAY_SIZE];
assign x[0] = '1;
for (j = 1; j < ARRAY_SIZE; j = j + 1)
 assign x[j][OUT_WIDTH*i +: OUT_WIDTH] = x[j-1][IN_WIDTH*i +: IN_WIDTH];
